# Generated by openai (gpt-4o-mini)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'BUILD_COMMAND', defaultValue: 'echo "No build command specified"', description: 'Custom build command to execute')
        string(name: 'TEST_SCRIPT', defaultValue: 'echo "No test script specified"', description: 'Custom test script to execute')
        string(name: 'DEPLOY_STEP', defaultValue: 'echo "No deployment step specified"', description: 'Custom deployment step to execute')
    }

    stages {
        stage('Build') {
            steps {
                script {
                    sh "${params.BUILD_COMMAND}"
                }
            }
        }
        stage('Test') {
            steps {
                script {
                    sh "${params.TEST_SCRIPT}"
                }
            }
        }
        stage('Deploy') {
            steps {
                script {
                    sh "${params.DEPLOY_STEP}"
                }
            }
        }
    }
}